import gsap from "gsap";
import { CustomEase } from "gsap/CustomEase";

document.addEventListener("DOMContentLoaded", () => {
  gsap.registerPlugin(CustomEase);
  CustomEase.create("hop", "0.75, 0, 0.2, 1");

  const introCards = document.querySelectorAll(".intro-cards .card");
  const introCardsCount = introCards.length;
  const radius = window.innerWidth < 1000 ? 150 : 225;

  // position each intro card in a circle
  introCards.forEach((card, i) => {
    const angle = (i / introCardsCount) * Math.PI * 2 - Math.PI / 2;

    const x = radius * Math.cos(angle);
    const y = radius * Math.sin(angle);

    gsap.set(card, {
      x: x,
      y: y,
      rotation: (angle * 180) / Math.PI + 90,
      transformPerspective: 800,
      transformOrigin: "center center",
      scale: 0,
    });
  });

  // position all outro cards at the same spot as the first intro card
  const outroCards = document.querySelectorAll(".outro-cards .card");

  const firstIntroCardAngle = (0 / introCardsCount) * Math.PI * 2 - Math.PI / 2;
  const firstIntroCardX = radius * Math.cos(firstIntroCardAngle);
  const firstIntroCardY = radius * Math.sin(firstIntroCardAngle);

  outroCards.forEach((card, index) => {
    gsap.set(card, {
      x: firstIntroCardX,
      y: firstIntroCardY,
      rotation: (firstIntroCardAngle * 180) / Math.PI + 90,
      rotationY: index === 0 ? 0 : 180,
      transformPerspective: 800,
      transformOrigin: "center center",
      zIndex: 5 - index,
      opacity: 0,
    });
  });

  // calculate card positions function
  const calculateCardPositions = () => {
    const viewportWidth = window.innerWidth;
    const cardRect = outroCards[0].getBoundingClientRect();
    const cardWidth = cardRect.width;
    const padding = viewportWidth < 1000 ? 16 : 32;
    const maxLeftPos = -(viewportWidth / 2) + padding + cardWidth / 2;
    const maxRightPos = viewportWidth / 2 - padding - cardWidth / 2;

    return [0, maxLeftPos, maxLeftPos / 2, maxRightPos / 2, maxRightPos];
  };

  // main animation timeline
  const tl = gsap.timeline({ delay: 0.5 });

  tl.to(introCards, {
    scale: 1,
    duration: 1,
    stagger: 0.1,
    ease: "hop",
    onComplete: () => {
      gsap.set(outroCards, { opacity: 1 });
      gsap.set(outroCards[0], { scale: 1, rotation: 0 });
      gsap.set(outroCards[1], { scale: 0.1, rotation: -90 });
      gsap.set(outroCards[2], { scale: 0.1, rotation: -45 });
      gsap.set(outroCards[3], { scale: 0.1, rotation: 90 });
      gsap.set(outroCards[4], { scale: 0.1, rotation: 45 });
    },
  });

  tl.to(introCards, {
    scale: 0,
    duration: 1,
    stagger: 0.1,
    ease: "hop",
  })
    .to(
      outroCards,
      {
        y: window.innerWidth < 1000 ? 0 : -125,
        duration: 1.5,
        ease: "hop",
      },
      "-=0.25"
    )
    .to(
      outroCards[0],
      {
        rotationY: 180,
        duration: 1.5,
        ease: "hop",
      },
      "<"
    )
    .to(
      outroCards,
      {
        x: (index) => calculateCardPositions()[index],
        scale: 1,
        rotation: 0,
        duration: 1.5,
        ease: "hop",
      },
      "<"
    )
    .to(
      "nav",
      {
        y: 0,
        duration: 1,
        ease: "hop",
      },
      "-=1"
    );

  // hero-footer animation timeline
  const heroFooterTl = gsap.timeline({ delay: 0.5 });

  heroFooterTl
    .to(".hero-footer .logo img", {
      y: "0%",
      duration: 1,
      ease: "hop",
    })
    .to(
      ".hero-footer .logo",
      {
        scale: 1,
        duration: 1.25,
        ease: "hop",
      },
      "+=2.25"
    );

  // recalculate card positions when window resizes
  const updateCardPositions = () => {
    const positions = calculateCardPositions();

    outroCards.forEach((card, index) => {
      gsap.set(card, { x: positions[index] });
    });
  };

  window.addEventListener("resize", updateCardPositions);
});

code.styles.css:
@import url("https://fonts.googleapis.com/css2?family=Barlow+Condensed:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;0,800;0,900;1,100;1,200;1,300;1,400;1,500;1,600;1,700;1,800;1,900&display=swap");

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "Barlow Condensed";
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

nav {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  padding: 1.5rem;
  display: flex;
  justify-content: space-between;
  gap: 2rem;
  transform: translateY(-100%);
  will-change: transform;
  z-index: 2;
}

nav > div {
  flex: 1;
}

nav .site-info {
  text-align: center;
}

nav .menu {
  text-align: right;
}

nav p {
  text-transform: uppercase;
  font-size: 1.25rem;
  font-weight: 700;
}

.container {
  position: relative;
  width: 100%;
  height: 100svh;
  padding: 2rem;
  background-color: #6c9a8b;
  overflow: hidden;
}

.intro-cards,
.outro-cards {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

.card {
  position: absolute;
  width: 100px;
  height: 138.09px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  transform-style: preserve-3d;
  will-change: transform;
}

.outro-cards .card:nth-child(2),
.outro-cards .card:nth-child(3) {
  transform-origin: right bottom;
}

.outro-cards .card:nth-child(4),
.outro-cards .card:nth-child(5) {
  transform-origin: left bottom;
}

.card-front,
.card-back {
  position: absolute;
  width: 100%;
  height: 100%;
  backface-visibility: hidden;
}

.card-front {
  display: flex;
  justify-content: space-between;
  padding: 0.75rem;
  background-color: #fbf7f4;
  color: #0e0e0e;
  transform: rotateY(180deg);
}

.card-front p {
  font-size: 1rem;
  font-weight: 700;
}

.hero-footer {
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  padding: 1.5rem 2rem;
  display: flex;
  justify-content: center;
}

.hero-footer .logo {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
  transform: scale(0.1);
  transform-origin: bottom;
  will-change: transform;
}

.hero-footer .logo img {
  position: relative;
  transform: translateY(125%);
}

.card {
  transform: translate(-50%, -50%) scale(0);
}

@media (max-width: 1000px) {
  nav {
    padding: 1rem;
    gap: 0;
  }

  .card {
    width: 60px;
    height: 83.44px;
  }

  .card-front {
    padding: 0.5rem;
  }

  .card-front p {
    font-size: 1rem;
  }

  .hero-footer {
    padding: 1rem;
  }

  .hero-footer .logo {
    transform: scale(0.5);
  }
}
